import { apiClient } from '../utils/apiClient';

export const authService = {
  register(payload) {
    return apiClient.post('/auth/register', payload);
  },

  login(payload) {
    return apiClient.post('/auth/login', payload);
  },

  me(token) {
    return apiClient.get('/auth/me', { token });
  }
};
